class Emitter {
  constructor() {
    this.events = {};
  }

  emit(event, ...args) {
    let callbacks = this.events[event] || [];
    for (let i = 0, length = callbacks.length; i < length; i++) {
      callbacks[i](...args);
    }
  }

  on(event, cb) {
    // Add the callback to the event's callback list, or create a new list with the callback
    this.events[event]?.push(cb) || (this.events[event] = [cb]);

    // Return an unsubscribe function
    return () => {
      this.events[event] = this.events[event]?.filter((i) => cb !== i);
    }
  }

  off(event, callback) {
    this.events[event] = this.events[event]?.filter((i) => callback !== i);
  }

  destroy() {
    this.events = {};
  }
}

function clamp(min, input, max) {
  return Math.max(min, Math.min(input, max));
}

function mix(a, b, lerp) {
  return a + (b - a) * lerp;
}

function damp(x, y, lambda, dt) {
  return lerp(x, y, 1 - Math.exp(-lambda * dt));
}

function lerp(s, e, t) {
  return round((1 - t) * s + t * e);
}

function mapTo(value, inMin, inMax, outMin, outMax, capped) {
  const newVal =
    ((value - inMin) * (outMax - outMin)) / (inMax - inMin) + outMin;

  {
    const max = outMin > outMax ? outMin : outMax;
    const min = outMin > outMax ? outMax : outMin;

    return clamp(min, newVal, max);
  }
}

function round(number, precision = 6) {
  const factor = Math.pow(10, precision);
  return Math.round(number * factor) / factor;
}

class VirtualScroll {
  constructor(
    element,
    { wheelMultiplier = 1, touchMultiplier = 2, normalizeWheel = false }
  ) {
    this.element = element;
    this.wheelMultiplier = wheelMultiplier;
    this.touchMultiplier = touchMultiplier;
    this.normalizeWheel = normalizeWheel;

    this.pointer = {
      active: false
    };

    this.touchStart = {
      x: null,
      y: null
    };

    this.lastDelta = {
      x: 0,
      y: 0
    };

    this.emitter = new Emitter();

    this.element.addEventListener('wheel', this.onWheel, { passive: false });
    if ('ontouchstart' in window) {
      this.element.addEventListener('touchstart', this.onTouchStart, {
        passive: false
      });
      this.element.addEventListener('touchmove', this.onTouchMove, {
        passive: false
      });
      this.element.addEventListener('touchend', this.onTouchEnd, {
        passive: false
      });
    } else {
      this.element.addEventListener('mousedown', this.onTouchStart, {
        passive: false
      });
      this.element.addEventListener('mousemove', this.onTouchMove, {
        passive: false
      });
      this.element.addEventListener('mouseup', this.onTouchEnd, {
        passive: false
      });
    }
  }

  // Add an event listener for the given event and callback
  on(event, callback) {
    return this.emitter.on(event, callback)
  }

  // Remove all event listeners and clean up
  destroy() {
    this.emitter.destroy();

    this.element.removeEventListener('wheel', this.onWheel, {
      passive: false
    });

    if ('ontouchstart' in window) {
      this.element.removeEventListener('touchstart', this.onTouchStart, {
        passive: false
      });
      this.element.removeEventListener('touchmove', this.onTouchMove, {
        passive: false
      });
      this.element.removeEventListener('touchend', this.onTouchEnd, {
        passive: false
      });
    } else {
      this.element.removeEventListener('mousedown', this.onTouchStart, {
        passive: false
      });
      this.element.removeEventListener('mousemove', this.onTouchMove, {
        passive: false
      });
      this.element.removeEventListener('mouseup', this.onTouchEnd, {
        passive: false
      });
    }
  }

  // Event handler for 'touchstart' event
  onTouchStart = (event) => {
    if (this.pointer.active) return

    this.pointer.active = true;

    const { clientX, clientY } = event.targetTouches
      ? event.targetTouches[0]
      : event;

    this.touchStart.x = clientX;
    this.touchStart.y = clientY;

    this.lastDelta = {
      x: 0,
      y: 0
    };

    this.emitter.emit('scroll', {
      deltaX: 0,
      deltaY: 0,
      event
    });
  }

  // Event handler for 'touchmove' event
  onTouchMove = (event) => {
    if (!this.pointer.active) return

    event.preventDefault();

    const { clientX, clientY } = event.targetTouches
      ? event.targetTouches[0]
      : event;

    const deltaX = -(clientX - this.touchStart.x) * this.touchMultiplier;
    const deltaY = -(clientY - this.touchStart.y) * this.touchMultiplier;

    this.touchStart.x = clientX;
    this.touchStart.y = clientY;

    this.lastDelta = {
      x: deltaX,
      y: deltaY
    };

    this.emitter.emit('scroll', {
      deltaX,
      deltaY,
      event
    });
  }

  onTouchEnd = (event) => {
    this.pointer.active = false;

    this.lastDelta = {
      x: 0,
      y: 0
    };

    this.emitter.emit('scroll', {
      deltaX: this.lastDelta.x,
      deltaY: this.lastDelta.y,
      event
    });
  }

  // Event handler for 'wheel' event
  onWheel = (event) => {
    let { deltaX, deltaY } = event;

    if (this.normalizeWheel) {
      deltaX = clamp(-5, deltaX, 5);
      deltaY = clamp(-5, deltaY, 5);
    }

    deltaX *= this.wheelMultiplier;
    deltaY *= this.wheelMultiplier;

    this.emitter.emit('scroll', { deltaX, deltaY, event });
  }
}

